{"type": "email", "id": "email_001", "subject": "Vehicle Ownership Duration Analysis", "from": "john.davidson@elexionautomotive.com", "from_name": "John Davidson", "to": ["emily.lee@elexionautomotive.com"], "cc": ["sarah.miller@elexionautomotive.com"], "date": "2025-01-11 09:20:45", "body": "Hi Emily, 

